INSERT INTO `mdt_penal_codes` (`code`, `label`, `charge_class`, `months`, `fine`, `color`, `description`) VALUES
('(0)01', 'Informações Gerais', 'misdemeanor', 0, 0, 'orange', 'Este documento deve ser reconhecido como o Código Penal, aplicável em todo o território do Estado de San Andreas, com efeito a partir da sua publicação.'),
('(0)02', 'Definições', 'misdemeanor', 0, 0, 'orange', 'O termo "Pessoa" refere-se a qualquer ser humano.'),
('(0)03', 'Do Entendimento Legal', 'felony', 0, 0, 'red', 'Não há ilegalidade na filmagem ou fotografia em locais públicos, salvo se estas colocarem pessoas em perigo ou se revelarem informações sensíveis: placas de veículos, documentos de identificação e endereços completos, os quais devem ser censurados das filmagens ou fotografias.'),
('(1)01', 'Traição', 'felony', 0, 0, 'red', 'O ato de declarar guerra contra os Estados Unidos ou aliar-se aos seus inimigos, fornecendo-lhes ajuda e/ou conforto, tanto dentro dos Estados Unidos como em qualquer outro lugar, em detrimento da lealdade para com o país.'),
('(1)02', 'Espionagem', 'felony', 0, 0, 'red', 'A prática intencional, ou sua tentativa, de obter, transmitir ou divulgar informações confidenciais que comprometam a segurança do Estado, sejam dados de defesa, instalações de saúde ou inteligência de comunicações dos Estados Unidos.'),
('(1)03', 'Terrorismo Doméstico', 'felony', 0, 0, 'red', 'Aquele que, com a intenção de amedrontar ou pressionar uma população civil, influenciar a política de um governo ou qualquer parte dele, ou afetar o comportamento de uma unidade governamental, praticar ou tentar cometer um ato criminoso que resultaria em ferimentos graves, lesões corporais ou morte.'),
('(1)04', 'Sonegação Tributária', 'felony', 20, 10000, 'red', 'Uma pessoa, de forma consciente e dentro do prazo legal, deixar de realizar, assinar, ratificar ou arquivar qualquer declaração exigida pelo estado, cidade, suas subdivisões ou qualquer órgão público.'),
('(1)05', 'Contrafação de Moeda', 'felony', 0, 0, 'red', 'A reprodução ilegítima e completa de moeda genuína levada a cabo por meios de cunhagem ou moldagem com a intenção de a colocar em circulação.'),
('(1)06', 'Fraude Eleitoral', 'felony', 20, 15000, 'red', 'Qualquer pessoa que tente manipular votos adicionando, subtraindo ou excluindo-os, ou falsificando os resultados de uma eleição, ou ainda influenciar indevidamente a votação através de coerção, persuasão, promessas, subornos, ameaças, violência, fraude ou trapaça.'),
('(1)07', 'Corrupção no Cargo Público', 'felony', 30, 0, 'red', 'Qualquer pessoa que, estando empregada por uma agência municipal, distrital ou estadual, ou agindo em conluio com um funcionário público, atue com a intenção de fraudar o governo ou qualquer parte dele para obter propriedade, serviços, recursos ou tratamento preferencial por meio de declarações falsas ou fraudulentas.'),
('(1)09', 'Suborno de um Funcionário Público', 'felony', 10, 0, 'red', 'Qualquer pessoa que ofereça ou concorde em dar dinheiro, bens, serviços, benefícios ou qualquer coisa de valor a um funcionário público para influenciar indevidamente sua ação oficial, opinião, julgamento, decisão ou exercício de discricionariedade.'),
('(1)10', 'Manipulação de Evidências', 'felony', 10, 0, 'red', 'Qualquer pessoa que deliberadamente modificar, alterar, fabricar, plantar, destruir, danificar, ocultar ou mover qualquer coisa usada como prova, com a intenção de impedir, enganar ou dificultar um processo legal ou de outra forma criar um efeito enganoso nesse processo.'),
('(1)11', 'Desacato ao Tribunal', 'misdemeanor', 40, 20000, 'orange', 'Qualquer pessoa cujo comportamento desordenado, desdenhoso ou insolente, praticado durante o funcionamento de um tribunal, na presença imediata do tribunal, contribua diretamente para interromper os procedimentos ou prejudicar o respeito devido à sua autoridade.'),
('(1)12', 'Perjúrio', 'felony', 30, 0, 'red', 'Qualquer pessoa que, tendo feito um juramento de testemunhar, declarar, depor ou certificar a verdade perante qualquer tribunal competente, oficial ou em um tribunal em sessão, intencionalmente e contrariando o juramento, declare como verdadeiro qualquer assunto material que sabe ser falso.'),
('(1)13', 'Obstrução de Justiça', 'felony', 10, 0, 'red', 'Qualquer pessoa que, por meio de intimidação, uso de força física ou através de um ato ilegal intencional, obstrua, prejudique ou corrompa deliberadamente a administração da justiça pública ou qualquer outra função governamental, ou tente impedir um funcionário público de cumprir sua função oficial com a intenção de causar danos.'),
('(1)14', 'Lavagem de Dinheiro', 'felony', 30, 0, 'red', 'Uma pessoa que possui, oculta, transfere, recebe ou mantém armazenamento de fundos obtidos por meio de atividades criminosas.'),
('(2)01', 'Incitação ao Tumulto', 'misdemeanor', 20, 0, 'orange', 'Qualquer pessoa que, com a intenção de causar tumulto, envolva-se em conduta tumultuosa ou violenta que incite um tumulto ou incite outros a cometer atos de violência, força ou destruição de propriedade em circunstâncias que gerem alarme público.'),
('(2)02', 'Intimidação de Testemunha ou Vítima', 'felony', 20, 0, 'red', 'Qualquer pessoa que, consciente e maliciosamente, impeça, dissuada ou tente impedir que uma testemunha ou vítima compareça ou preste depoimento em qualquer processo judicial ou inquérito, ou faça uma denúncia que possa levar a uma ação criminal.'),
('(2)03', 'Fuga da Custódia Legal', 'felony', 20, 0, 'red', 'Qualquer pessoa que esteja presa, detida, acusada ou condenada por um crime e que, posteriormente, escape de uma prisão municipal ou do condado, centro de detenção, serviço comunitário ou da custódia de um agente penitenciário responsável por sua guarda.'),
('(2)04', 'Evasão de um Oficial de Paz', 'felony', 10, 200, 'red', 'Qualquer pessoa que, ao dirigir um veículo motorizado, andar de bicicleta ou de outra forma, tente intencionalmente escapar ou evadir-se de um oficial de paz.'),
('(2)05', 'Resistência', 'misdemeanor', 15, 0, 'orange', 'Qualquer pessoa que intencionalmente atrasar, evitar, obstruir ou tentar impedir que um oficial de paz realize sua prisão.'),
('(2)06', 'Uso Indevido de Canal de Emergência', 'misdemeanor', 15, 200, 'orange', 'Qualquer pessoa que use uma linha direta do governo, destinada a assistência emergencial ou não emergencial, com o propósito de entrar em contato com o governo por uma preocupação legítima ou solicitar assistência imediata, para fins diferentes, como realizar trotes, fazer piadas ou causar distrações.'),
('(2)07', 'Falsidade Ideológica', 'misdemeanor', 0, 0, 'orange', 'Qualquer pessoa que se faça passar por outra pessoa.'),
('(2)08', 'Agressão a um Agente do Governo', 'felony', 20, 0, 'red', 'Qualquer pessoa que tente ferir, mutilar ou de qualquer outra forma prejudicar um membro do governo durante o desempenho de suas funções oficiais.'),
('(2)09', 'Falsificação', 'misdemeanor', 30, 0, 'orange', 'Qualquer pessoa que, conscientemente, crie, complete ou altere um documento escrito com a intenção de fraudar, enganar ou prejudicar outra pessoa.'),
('(2)10', 'Fraude', 'misdemeanor', 30, 10000, 'orange', 'Qualquer pessoa que, conscientemente, engane, defraude, ludibrie ou engane outra pessoa por meio de representações falsas, ocultação de fatos relevantes, manipulação de informações, falsificação de documentos ou qualquer outro meio fraudulento, com o objetivo de obter benefícios financeiros, bens materiais ou vantagens pessoais indevidas.'),
('(2)11', 'Perturbação da Paz', 'misdemeanor', 10, 2500, 'orange', 'Qualquer pessoa que, de forma indecente, cause perturbação através de música alta, palavras ofensivas ou vulgares, ou qualquer conduta que perturbe as atividades ou a tranquilidade da comunidade.'),
('(2)12', 'Extorsão', 'felony', 15, 0, 'red', 'É ilegal para qualquer pessoa, grupo ou organização conscientemente se envolver, participar ou conspirar para se envolver em um padrão de atividade de extorsão, incluindo a cobrança de uma dívida ilegal, em benefício de uma empresa, associação ou emprego.'),
('(3)01', 'Homicídio Capital', 'felony', 20, 0, 'red', 'Qualquer indivíduo que intencionalmente tire a vida de um policial, bombeiro, paramédico, promotor, juiz, jurado ou outro funcionário eleito no desempenho de suas funções, ou qualquer testemunha em um processo criminal.'),
('(3)02', 'Homicídio Culposo', 'felony', 10, 0, 'red', 'Qualquer pessoa que esteja envolvida na morte não intencional de outra pessoa, sem malícia, seja durante uma briga súbita, por paixão intensa ou qualquer pessoa que cause intencionalmente a morte de outra pessoa sob uma crença irracional de que o uso letal da força é necessário (defesa própria incorreta).'),
('(3)03', 'Homicídio Doloso', 'felony', 15, 0, 'red', 'Qualquer pessoa que esteja envolvida na morte intencional de outra pessoa, e age com a intenção de causar sua morte.'),
('(3)04', 'Ameaça de Lesão', 'misdemeanor', 5, 0, 'orange', 'Qualquer pessoa que tente cometer ilegalmente qualquer forma de violência física contra outra pessoa ou tente criar um sentimento razoável de medo de ferimentos físicos.'),
('(3)05', 'Agressão com Arma Mortal', 'felony', 5, 0, 'red', 'Qualquer pessoa que tente cometer uma lesão violenta em outra pessoa enquanto estiver portando uma arma letal ou qualquer outro instrumento com possibilidade de infligir dano físico.'),
('(3)06', 'Lesão Corporal Leve', 'misdemeanor', 10, 0, 'orange', 'Refere-se a qualquer indivíduo que intencionalmente e ilegalmente utilize força física sobre outra pessoa, causando lesões corporais leves, sem risco iminente de morte.'),
('(3)07', 'Lesão Corporal Grave', 'felony', 20, 0, 'red', 'Diz respeito a qualquer indivíduo que intencionalmente e ilegalmente utilize força física sobre outra pessoa, resultando em lesões corporais graves, com acometimento de órgãos vitais.'),
('(3)08', 'Sequestro', 'felony', 30, 0, 'red', 'Refere-se a qualquer pessoa que, de forma forçada ou por meio de ameaça, roube, tome, detenha ou prenda ilegalmente outra pessoa com a intenção de levá-la para outro país, estado, município ou parte do mesmo condado ou cidade.'),
('(3)09', 'Tráfico de Pessoas', 'felony', 60, 0, 'red', 'Refere-se a qualquer pessoa que, por meio de coerção, violência, força ou outros meios ilícitos, priva alguém de sua liberdade pessoal com a intenção de explorar trabalho forçado ou serviços, ou com a intenção de violar as leis de prostituição e exploração sexual em San Andreas.'),
('(3)10', 'Cárcere', 'misdemeanor', 20, 0, 'orange', 'Diz respeito a qualquer pessoa que, por meio de força ou ameaça, detenha ou prenda ilegalmente outra pessoa.'),
('(3)11', 'Tortura', 'felony', 90, 0, 'red', 'Refere-se a qualquer pessoa que, com a intenção de causar dor e sofrimento cruel ou extremo por vingança, extorsão, persuasão ou qualquer propósito sádico, cause grave lesão corporal a outra pessoa.'),
('(3)12', 'Ameaça Criminosa', 'felony', 10, 0, 'red', 'Qualquer pessoa que ameace deliberadamente cometer um crime que razoavelmente possa resultar em morte ou lesão corporal a outra pessoa, seja por meio de palavras, por escrito ou por dispositivos de comunicação eletrônica.'),
('(3)13', 'Roubo', 'felony', 10, 0, 'red', 'Refere-se a qualquer pessoa que cometa apropriação ilegal de bens pessoais de outra pessoa, contra a vontade dela e em sua posse imediata, utilizando força ou ameaça.'),
('(3)14', 'Roubo Armado', 'felony', 20, 0, 'red', 'Qualquer pessoa que, ilegalmente, se aproprie de bens pessoais de outra pessoa ou em sua posse imediata, utilizando força ou ameaça com o uso de uma arma perigosa ou qualquer tipo de arma, seja improvisada ou não.'),
('(3)15', 'Estupro', 'felony', 60, 0, 'red', 'Qualquer pessoa que se envolve em um ato sexual realizado sem o consentimento das partes envolvidas.'),
('(3)16', 'Estupro de Vulnerável', 'felony', 60, 0, 'red', 'Qualquer pessoa que pratique ato sexual consensual com um indivíduo menor de 18 anos ou legalmente considerado dependente do estado.'),
('(3)17', 'Assédio Sexual', 'felony', 20, 0, 'red', 'Qualquer pessoa que toque uma parte íntima do corpo de outra pessoa contra a vontade dela, com o propósito de excitação sexual, gratificação sexual ou abuso sexual.'),
('(3)18', 'Assédio', 'misdemeanor', 20, 0, 'orange', 'Qualquer pessoa que se envolve em um padrão de comportamento ou atos repetidos direcionados a uma pessoa específica, que causem alarme ou angústia significativa a essa pessoa e não tenham propósito legítimo, mesmo após receber uma comunicação verbal ou escrita para parar. Se não for possível a comunicação escrita ou verbal, a intenção criminosa deve ser estabelecida.'),
('(3)19', 'Violência Doméstica', 'misdemeanor', 20, 0, 'orange', 'Refere-se a qualquer pessoa que se envolve em um padrão de comportamento ou atos repetidos direcionados a uma pessoa específica, que causem alarme significativo a essa pessoa e não tenham propósito legítimo, mesmo após receber uma advertência verbal ou escrita para parar. Se não for possível a advertência escrita ou verbal, a intenção criminosa deve ser considerada.'),
('(3)20', 'Vilipêndio a Cadáver', 'felony', 20, 0, 'red', 'Vilipendiar, mutilar, danificar, desrespeitar, expor à terceiros pessoalmente ou de maneira midiática através de fotografias ou vídeos cadáveres humanos e animais ou suas partes, como membros ou cinzas.'),
('(4)01', 'Incêndio Criminoso', 'felony', 5, 0, 'red', 'Ação intencional e maliciosa de provocar fogo, queimar ou auxiliar na queima de estruturas, áreas florestais ou propriedades, sem autorização legal.'),
('(4)02', 'Arrombamento', 'felony', 5, 0, 'red', 'Refere-se à invasão ilegal e não autorizada de estruturas comerciais ou residenciais desocupadas, seja propriedade pública ou privada, com o objetivo de obter itens de forma ilícita ou cometer um crime no local.'),
('(4)03', 'Invasão de Domicílio', 'felony', 5, 0, 'red', 'Invasão de residências ocupadas, sabendo ou não se há pessoas presentes, com o objetivo de obter itens de forma ilícita ou cometer um crime no local.'),
('(4)04', 'Roubo Majorado', 'felony', 15, 5501, 'red', 'Apropriação ilegal, roubo, transporte ou remoção de propriedade pessoal de outra pessoa ou organização no valor de US$5.501 ou mais.'),
('(4)05', 'Roubo Minorado', 'felony', 5, 5500, 'red', 'Apropriação ilegal, roubo, transporte ou remoção de propriedade pessoal de outra pessoa ou organização no valor de US$5.500 ou menos.'),
('(4)06', 'Roubo de Veículo', 'felony', 5, 0, 'red', 'Ato de roubar, tentar roubar, conduzir ou utilizar o veículo de outra pessoa sem permissão.'),
('(4)07', 'Roubo de Arma de Fogo', 'felony', 10, 0, 'red', 'Refere-se ao roubo de qualquer arma de fogo registrada, independentemente de seu valor.'),
('(4)08', 'Posse de Ferramentas de Invasão', 'misdemeanor', 5, 1650, 'orange', 'Posse de instrumentos, tais como gazua, pé de cabra, chave de fenda, broca, lima, alicate ou qualquer outra ferramenta, quando essa posse está acompanhada de circunstâncias que permitam identificar a intenção subjacente de utilizá-los para cometer invasões ilegais.'),
('(4)09', 'Receptação', 'misdemeanor', 10, 0, 'orange', 'Refere-se à compra ou recebimento de propriedade que tenha sido roubada ou adquirida de forma ilícita, conhecendo a situação ou tendo conhecimento de que a propriedade seja provavelmente de origem criminosa, mas preferindo ignorar.'),
('(4)10', 'Invasão', 'misdemeanor', 20, 2000, 'orange', 'Refere-se à entrada em propriedade alheia com a intenção de interferir ou obstruir atividades comerciais em andamento, ou à ocupação de propriedade privada sem permissão, ou à recusa em deixar a propriedade privada após ser solicitado por proprietário, gerente, residente ou funcionário.'),
('(4)11', 'Vandalismo', 'misdemeanor', 10, 2500, 'orange', 'Refere-se a qualquer ato de desfiguração, dano ou destruição de propriedade alheia, excluindo incêndios.'),
('(4)12', 'Peculato', 'misdemeanor', 0, 0, 'orange', 'Situações em que há uma relação de confiança ou fiduciária entre o infrator e uma organização privada ou órgão governamental (estadual ou local):'),
('(5)01', 'Exposição Indecente', 'misdemeanor', 10, 20000, 'orange', 'Qualquer indivíduo que exiba deliberada e lascivamente seu corpo ou partes íntimas em espaços públicos ou em locais onde haja presença de outras pessoas.'),
('(5)02', 'Conduta Obscena ou Dissoluta em Público', 'misdemeanor', 20, 20000, 'orange', 'Qualquer pessoa que solicite ou participe de comportamento obsceno, dissoluto ou inadequado em locais públicos ou em áreas abertas ao público e expostas à visão do público.'),
('(5)03', 'Prostituição', 'misdemeanor', 15, 0, 'orange', 'Qualquer pessoa que encoraje ou convença outra pessoa a se envolver em atividades sexuais em troca de dinheiro, seja como agente atuante ou cliente.'),
('(5)04', 'Rufianismo', 'felony', 40, 0, 'red', 'Qualquer pessoa que encoraje ou convença outra pessoa a se envolver em atividades sexuais em troca de dinheiro, seja como prostituta ou cliente.'),
('(5)05', 'Perseguição', 'misdemeanor', 15, 0, 'orange', 'Qualquer pessoa que siga deliberada, maliciosa e repetidamente outra pessoa, causando temor razoável em relação à segurança dessa pessoa ou de sua família, ao assediar intencionalmente ou fazer ameaças críveis.'),
('(5)06', 'Fraude em Jogos', 'misdemeanor', 15, 0, 'orange', 'Qualquer pessoa que, por meio de dispositivos, truques, enganos  ou outros meios, obtenha fraudulentamente dinheiro ou propriedade de outra pessoa durante jogos ou apostas, seja por meio de cartas ou outros instrumentos.'),
('(5)07', 'Abuso Infantil', 'felony', 80, 0, 'red', 'Qualquer pessoa que intencionalmente infligir punição corporal cruel ou desumana, causar lesões traumáticas ou colocar uma criança em situação que possa resultar em danos físicos graves, ou causar danos ou lesões menores a uma criança com menos de 18 anos.'),
('(5)08', 'Negligência Infantil', 'felony', 20, 0, 'red', 'Qualquer pessoa que falhe em fornecer as necessidades físicas básicas, como roupas, comida, abrigo, cuidados médicos ou outros cuidados adequados, a um filho menor sem justificativa legal.'),
('(5)09', 'Venda de Álcool / Tabaco para um Menor', 'infraction', 0, 15000, 'green', 'Qualquer pessoa que venda deliberadamente e conscientemente álcool e/ou tabaco a um indivíduo com menos de 18 anos.'),
('(5)10', 'Violação de Álcool / Tabaco por um Menor', 'misdemeanor', 10, 0, 'orange', 'Qualquer pessoa com menos de 18 anos que esteja em posse de álcool, produtos à base de álcool ou aparente estar sob a influência de álcool ou qualquer produto à base de tabaco.'),
('(5)11', 'Abuso Animal', 'felony', 20, 0, 'red', 'Qualquer pessoa que maliciosamente e intencionalmente machuque, mutila, torture, agrida, fira ou mate um animal vivo, ou que possua um animal de estimação que não seja considerado domesticado e seguro para o animal ou o dono.'),
('(5)12', 'Exercício Ilegal da Profissão', 'felony', 20, 0, 'red', 'Uma pessoa que se identifica como detentora de uma licença para prática da medicina, verbalmente ou por meios implícitos, e que não recebeu treinamento adequado para fazê-lo.'),
('(6)01', 'Manufatura de Substância Ilícita', 'felony', 20, 0, 'red', 'Qualquer indivíduo que produza, componha, converta, fabrique, derive, processe ou prepare qualquer substância proibida, seja por meio de produtos químicos ou extração da natureza, sem as devidas autorizações. A penalidade geral será determinada pela classificação mais alta da substância fabricada.'),
('(6)02', 'Posse de Substância Controlada', 'infraction', 0, 2000, 'green', 'Qualquer pessoa que esteja em posse de uma ou várias substâncias controladas, exceto nos casos em que haja prescrição ou dispensação direta por parte de um profissional licenciado pelo estado para prescrever, dispensar ou administrar substâncias controladas. Isso se aplica a quantidades inferiores a 10 gramas. A penalidade geral será determinada pela classificação mais alta da substância em posse.'),
('(6)03', 'Posse de Substância Controlada com Intenção de Distribuição', 'misdemeanor', 15, 0, 'orange', 'Qualquer pessoa que esteja em posse de uma ou várias substâncias controladas com a intenção de distribuí-las, entregá-las ou vendê-las. Isso se aplica automaticamente a quantidades iguais ou superiores a 10 gramas, independentemente da intenção. A penalidade geral será determinada pela classificação mais alta da substância em posse.'),
('(6)04', 'Comércio Ilegal de Substância Controlada', 'felony', 20, 0, 'red', 'Qualquer pessoa que comercialize, de forma consciente e ilegal, uma ou mais preparações, compostos ou misturas que contenham substâncias controladas. A penalidade geral será determinada pela classificação mais alta da substância em posse.'),
('(6)05', 'Contrabando de Drogas', 'felony', 10, 0, 'red', 'Qualquer pessoa que tente ou consiga transportar, exportar, armazenar ou ocultar substâncias controladas em sua pessoa ou em uma propriedade, em quantidades superiores a 20 gramas, independentemente da intenção. A penalidade geral será determinada pela classificação mais alta da substância em posse.'),
('(6)06', 'Tráfico de Drogas', 'felony', 35, 0, 'red', 'Qualquer pessoa que tente ou consiga transportar, importar ou exportar uma ou várias substâncias controladas em sua pessoa ou em uma propriedade, em quantidades superiores a 40 gramas, independentemente da intenção. A penalidade geral será determinada pela classificação mais alta da substância em posse.'),
('(6)07', 'Posse de Artefato para Consumo de Drogas', 'infraction', 0, 5000, 'green', 'Qualquer indivíduo que esteja ciente de estar em posse de qualquer dispositivo, instrumento ou artefato utilizado ou destinado ao consumo ilegal de substâncias ilícitas, seja por via intravenosa ou inalação.'),
('(6)08', 'Porte Velado de Arma Branca', 'misdemeanor', 10, 0, 'orange', 'Qualquer pessoa que portar de forma oculta ou dissimulada uma arma branca laminada, cortante, perfurante ou similares, com indícios de que pretende usá-la contra terceiros.'),
('(6)09', 'Violação de Confidencialidade', 'felony', 40, 0, 'red', 'Qualquer pessoa que se envolver ilegalmente em escutas telefônicas, gravações mecânicas de conversas, interceptação ou acesso a comunicações eletrônicas.'),
('(6)10', 'Obstrução Facial', 'felony', 10, 0, 'red', 'Qualquer pessoa que obstruir ou ocultar seu rosto durante a prática de um crime ou antes de tal prática, havendo indícios substanciais de que o crime ocorreria.'),
('(6)11', 'Violação do Código de Incêndio', 'infraction', 0, 35000, 'green', 'Qualquer violação do Código de Incêndio estabelecido pelo State Fire Marshal.'),
('(6)12', 'Descarte Inadequado', 'infraction', 0, 1200, 'green', 'Qualquer pessoa que descartar, jogar ou espalhar lixo ou resíduos em local impróprio, seja em público ou em propriedade privada que não seja sua própria.'),
('(6)13', 'Posse de Arma de Fogo Não Autorizada', 'misdemeanor', 0, 0, 'orange', 'Portar uma arma de fogo consigo, em seu veículo, local de trabalho ou em qualquer estabelecimento privado sem a documentação adequada ou sem o conhecimento ou consentimento (implícito ou explícito) de um indivíduo autorizado dentro do veículo, local de trabalho ou estabelecimento privado que possua tal autorização. Isso também se aplica a armas de fogo sem um número de série válido.'),
('(6)13-A', 'Posse de Arma de Fogo Não Autorizada Classe I', 'misdemeanor', 30, 0, 'orange', 'Pistolas e SMGs'),
('(6)13-B', 'Posse de Arma de Fogo Não Autorizada Classe II', 'misdemeanor', 60, 0, 'orange', 'Shotguns e Rifles de Assalto'),
('(6)14', 'Posse Ilegal de Arma de Fogo', 'felony', 0, 0, 'red', 'Qualquer pessoa que possua uma arma de fogo proibida pela lei estadual ou federal, faça uso de modificações ilegais em sua arma, ou possua armas de fogo que são proibidas de entrar, serem vendidas ou transportadas para o estado de San Andreas sem a autorização adequada.'),
('(6)14-A', 'Posse Ilegal de Armamento Classe III', 'misdemeanor', 60, 0, 'orange', 'LMGs e Armas Químicas'),
('(6)14-B', 'Posse Ilegal de Armamento Classe IV', 'misdemeanor', 100, 0, 'orange', 'Rifles de Precisão e Armas Pesadas'),
('(6)15', 'Posse Agravada de Arma de Fogo', 'felony', 60, 0, 'red', 'Qualquer pessoa que esteja em posse de mais de cinco armas de fogo não licenciadas, consigo, em seu veículo, local de trabalho ou em outro estabelecimento privado, ou mais de três armas de fogo proibidas de acordo com o artigo.'),
('(6)16', 'Posse de Dispositivo Incendiário ou Explosivo', 'felony', 80, 0, 'red', 'Qualquer pessoa que possua qualquer dispositivo incendiário ou explosivo proibido pela lei estadual ou federal, ou possua dispositivos que são proibidos de entrar, serem vendidos ou transportados para o estado de San Andreas sem a autorização adequada.'),
('(6)17', 'Venda Não Licenciada de Arma de Fogo ou Explosivo', 'felony', 20, 0, 'red', 'Qualquer pessoa que venda, dê ou compre ilegalmente armas de fogo, explosivos, dispositivos incendiários ou qualquer outro dispositivo similar ou improvisado de qualquer tipo sem as autorizações ou permissões adequadas.'),
('(6)18', 'Porte Ostensivo de Armamento', 'felony', 20, 0, 'red', 'Qualquer pessoa que, a menos que em legítima defesa, durante a presença de outros, exiba, segure, aponte ou brande uma arma branca, arma de fogo ou objeto similar de maneira ameaçadora, exaltada ou intimidadora, esteja ela carregada ou descarregada, com o objetivo de causar medo em outras pessoas.'),
('(6)19', 'Disparo de Arma de Fogo', 'felony', 20, 0, 'red', 'Qualquer pessoa que dispare intencionalmente uma arma de fogo, exceto quando em veículo, colocando vidas em risco e causando danos físicos ou risco de danos físicos a outras pessoas.'),
('(6)20', 'Disparo de Arma de Fogo de Dentro de um Veículo', 'felony', 30, 0, 'red', 'Qualquer motorista ou proprietário de um veículo que permita conscientemente que qualquer outra pessoa dispare uma arma de fogo dentro de um veículo motorizado.'),
('(6)21', 'Manuseio Imprudente de Arma de Fogo', 'misdemeanor', 10, 0, 'orange', 'Qualquer pessoa que manuseie negligentemente uma arma de fogo de forma a colocar em risco a vida, integridade física ou propriedade de outra pessoa.'),
('(6)22', 'Posse de Arma de Fogo por Criminoso Condenado', 'felony', 30, 0, 'red', 'Qualquer pessoa que porte ou possua uma arma de fogo em sua pessoa, veículo, local de trabalho ou outro estabelecimento que seja de sua propriedade ou que estejam diretamente sob sua administração, sendo um criminoso condenado por um crime conforme as leis dos Estados Unidos ou do estado de San Andreas.'),
('(6)23', 'Caça Ilegal', 'felony', 20, 0, 'red', 'Qualquer pessoa que, tendo sido proibida por lei ou por falta de licença adequada, capture, cace, pesque ou persiga animais selvagens protegidos ou em áreas designadas, infringindo as regulamentações de caça estabelecidas pelas autoridades competentes.'),
('(7)00', 'Das Limitações', 'misdemeanor', 0, 0, 'orange', 'Nenhum indivíduo pode receber mais de três avisos na licença de motorista, equivalentes a uma revogação de licença única, por incidente de lei rodoviária.'),
('(7)01', 'Condução Sem Licença Válida', 'infraction', 10, 2500, 'green', 'Dirigir um veículo automotor em via pública sem possuir uma habilitação válida para o tipo veicular.'),
('(7)02', 'Condução Com Licença Suspensa', 'infraction', 10, 5000, 'green', 'Dirigir um veículo automotor em via pública com a habilitação suspensa ou cassada.'),
('(7)03', 'Omissão De Socorro', 'misdemeanor', 20, 0, 'orange', 'O condutor de um veículo deixa de prestar socorro imediato à vítima em caso de acidente de trânsito, ou, caso não seja possível prestar socorro diretamente por motivo justificável, deixa de solicitar auxílio das autoridades públicas. Isso inclui omissão mesmo quando a vítima faleceu instantaneamente ou possui ferimentos leves.'),
('(7)04', 'Direção Perigosa', 'misdemeanor', 10, 5000, 'orange', 'Conduzir um veículo sem cuidado ou cautela, demonstrando desrespeito flagrante pela segurança de outras pessoas, agindo de maneira grosseiramente negligente e colocando em risco a vida, a integridade física ou a propriedade de qualquer pessoa.'),
('(7)05', 'Direção Perigosa De Veículo Terrestre Ou Naval', 'misdemeanor', 10, 5000, 'orange', 'Uso imprudente ou descuidado de um veículo terrestre ou naval, seja intencionalmente ou não, criando risco de causar ferimentos. Isso inclui veículos como ATVs, carros de golfe, barcos e embarcações navais, ou qualquer outro equipamento terrestre que não seja destinado a ser conduzido em estradas.'),
('(7)06', 'Excesso de Velocidade', 'infraction', 0, 2000, 'green', 'Em todos os momentos e em qualquer local oficial, incluindo rodovias estaduais, municipais e estradas locais, os motoristas devem respeitar os seguintes limites de velocidade:'),
('(7)07', 'Desrespeito aos Dispositivos de Tráfego', 'infraction', 0, 2500, 'green', 'Não obedecer aos dispositivos de controle de tráfego, tais como:'),
('(7)08', 'Estacionamento Irregular', 'infraction', 0, 5000, 'green', 'Qualquer veículo estacionado de forma irregular, como em:'),
('(7)09', 'Estacionamento Ilegal', 'infraction', 30, 10000, 'green', 'Qualquer veículo estacionado de forma ilegal, como em:'),
('(7)10', 'Violação de Veículos Ruidosos', 'infraction', 0, 1000, 'green', 'Conduzir veículo emitindo ruído excessivo através do uso desnecessário da buzina ou da reprodução de música alta, sem considerar a poluição sonora.'),
('(7)11', 'Operação Negligente de um Veículo', 'infraction', 0, 3000, 'green', 'Qualquer pessoa que opere um veículo de forma negligente, colocando em risco a integridade física de outras pessoas ou causando danos a outros veículos ou indivíduos. Exemplos disso incluem o uso de mensagens de texto durante a condução, dirigir sem acender as luzes no período entre o pôr do sol e o nascer do sol (os faróis devem ser utilizados entre as 18h00 e as 6h00).'),
('(7)12', 'Uso Ilegal de Equipamento Hidráulico', 'infraction', 20, 5000, 'green', 'Operar um veículo equipado com sistema hidráulico instalado no chassi ou em outros componentes do veículo, sem a necessidade ou finalidade legítima desse equipamento (como uma empilhadeira), não pode utilizar tal sistema hidráulico em estradas estaduais, municipais ou locais.'),
('(7)13', 'Vidros com Coloração Irregular', 'infraction', 10, 3000, 'green', 'Operar um veículo e utilizar irregularmente películas ou persianas nas janelas (de nível 1 ou 2), resultando em dificuldade de identificar o condutor do veículo.'),
('(7)14', 'Condução sob Influência de Álcool ou Drogas', 'misdemeanor', 10, 0, 'orange', 'Dirigir ou operar um veículo ou máquina sob a influência de álcool acima do limite legal de 0,08% BAC ou sob a influência de drogas que afetem o desempenho, independentemente de essas drogas serem legais ou ilegais.'),
('(7)15', 'Competição de Veículos Motorizados', 'misdemeanor', 10, 5000, 'orange', 'Realizar corridas ou competições não licenciadas ou não autorizadas em estradas ou vias pavimentadas da cidade, condado ou estado, que incentivem a ocorrência de outras infrações ou representem um perigo potencial.'),
('(7)16', 'Perigo Veicular', 'felony', 35, 10000, 'red', 'Operar um veículo causando perigo grave, dano físico real ou risco de dano físico a pedestres, ou dirija de maneira que coloque o público em risco grave.'),
('(7)17', 'Atravessar a Via de Forma Perigosa', 'infraction', 0, 1000, 'green', 'Qualquer pessoa que, intencionalmente ou de forma imprudente, atravessar uma via como pedestre de maneira que crie um risco previsível de obstrução do fluxo de tráfego ou de outra forma representa um perigo para os usuários da via.'),
('(7)18', 'Posse de Recipiente Aberto', 'infraction', 0, 3000, 'green', 'Qualquer pessoa que possua recipientes abertos contendo bebidas alcoólicas ou qualquer substância que altere o desempenho durante a condução de um veículo.'),
('(7)19', 'Falha no Uso de Cinto/Equipamento de Segurança', 'infraction', 0, 2000, 'green', 'Qualquer pessoa que, ao conduzir um veículo motorizado, não utilize o cinto de segurança de maneira adequada ou não cumpra os padrões de segurança no trânsito ao conduzir veículos como motocicletas, quadriciclos e outros veículos motorizados sem capacete ou outro equipamento de segurança adequado.'),
('(7)20', 'Operação de Veículo Motorizado em Condições Inseguras', 'infraction', 20, 5000, 'green', 'Conduzir ou mover um veículo motorizado, motocicleta ou combinação de veículos em vias públicas em condições inseguras que representem risco para qualquer pessoa ou propriedade, resultem em danos estruturais substanciais ou que não estejam equipados com luzes, freios, direção e outros equipamentos em bom estado.'),
('(7)21', 'Operação de Veículo Motorizado Não Registrado ou sem Identificação', 'infraction', 30, 3000, 'green', 'Dirigir, movimentar ou sair em uma via pública utilizando um veículo motorizado não registrado ou que não exiba placa de identificação, ou que deixe de pagar o seguro veicular dentro do prazo estabelecido por lei.'),
('(7)22', 'Operar uma Aeronave sem Licença', 'misdemeanor', 20, 30000, 'orange', 'Qualquer pessoa que opere qualquer tipo de aeronave sem uma licença apropriada.'),
('(7)23', 'Operar uma Aeronave em Risco à Vida', 'felony', 35, 70000, 'red', 'Colocar em risco a vida por meio da operação de uma aeronave, como voar em baixa altitude em área urbana ou suburbana, realizar manobras aéreas de forma negligente.'),
('(7)24', 'Falha em Obedecer aos Protocolos do ATC', 'felony', 10, 50000, 'red', 'Qualquer pessoa que, ao operar uma aeronave, deixe de obedecer aos protocolos do ATC (Controle de Tráfego Aéreo) e seus comandos.'),
('(7)25', 'Evasão Aérea', 'felony', 60, 150000, 'red', 'Evadir de um oficial de paz utilizando uma aeronave, seja como piloto, copiloto ou passageiro.'),
('(7)26', 'Operação Negligente de uma Bicicleta', 'infraction', 0, 2000, 'green', 'Qualquer pessoa que conduza uma bicicleta de forma que provavelmente cause danos materiais ou lesões a outros usuários da via ou pedestres estará cometendo.'),
('(7)27', 'Operação de Veículo Não Autorizado', 'infraction', 30, 7000, 'green', 'Qualquer pessoa envolvida na operação ou uso ilegal de um veículo impróprio na praia.'),
('(8)01', 'Erro de Fato', 'infraction', 0, 0, 'green', 'Se uma pessoa acusada de um crime alegar, e apresentar provas, de que agiu honestamente embora tenha cometido uma contravenção por circunstâncias adversas, na convicção de que não estava violando a lei ou não entendia que a lei que foi violada.'),
('(8)02', 'Intoxicação Involuntária', 'misdemeanor', 0, 0, 'orange', 'Aquele que, sob efeito de substâncias psicoativas, comete crime não pode ser acusado por não possuir plena consciência de seus atos. Essa prática de defesa necessita de provas devidamente fundamentadas de que o agente foi intoxicado pela ação de terceiros e o cometimento do crime aconteceu de maneira inconsciente.'),
('(8)03', 'Legítima Defesa', 'misdemeanor', 0, 0, 'orange', 'Uma pessoa que usando moderadamente dos meios necessários, repele injusta agressão, atual ou iminente, a direito seu ou de outrem é absolvida de responsabilidade criminal se apresentar provas.'),
('(8)04', 'Armadilha', 'felony', 0, 0, 'red', 'Uma pessoa que cometeu um crime, seja pelo assédio, ameaças ou coerção para fazê-lo por agentes da lei, não pode ser considerada culpada do crime em que foi persuadida a cometer.'),
('(8)05', 'Coação', 'felony', 0, 0, 'red', 'Uma pessoa que por força de coação, ameaça de autoridade superior ou por violenta emoção comete um crime não poderá ser acusada deste. Que fique provado o cometimento do crime sob essas circunstâncias.'),
('(8)06', 'Exclusões de Liberdade Condicional', 'misdemeanor', 0, 0, 'orange', 'Uma pessoa culpada de (3)11. Tortura, (3)03. Homicídio Doloso, (3)01. Homicídio Capital, (3)09. Tráfico de Pessoas, (1)02. Espionagem, (1)01. Traição ou (1)03. Terrorismo Doméstico deve ser sempre excluída de qualquer oportunidade de liberdade condicional.'),
('(8)07', 'Política de Suspeitas', 'felony', 60, 0, 'red', 'A suspeita justificável de um oficial da lei de uma pessoa cometer ou conspirar para cometer um crime é suficiente para permitir que esse indivíduo seja detido para interrogatório por no máximo 60 minutos pela polícia ou na custódia judicial, no entanto, eles não podem receber nada além de uma revista corporal para a segurança do oficial pela causa provável, a menos que existam provas da contravenção ou fundada suspeita.'),
('(8)08', 'Critério do Oficial', 'infraction', 0, 0, 'green', 'Os agentes da lei devem ter autoridade para usar seu critério ao emitir infrações ou contrair contravenções. Este critério confere ao oficial a possibilidade de renunciar a uma infração ou contravenção penal com base em seu julgamento pessoal.'),
('(8)09', 'Cláusula do Bom Samaritano', 'infraction', 0, 0, 'green', 'Os cidadãos podem realizar uma detenção judicial legal quando um indivíduo cometeu uma infração e o cidadão deseja deter o infrator até que as autoridades competentes possam chegar para apoiar, ajudar ou avaliar a situação.'),
('(8)10', 'Critérios de Prisão e Punição', 'misdemeanor', 30, 0, 'orange', 'Somente as violações criminais que se originam do Código Penal de San Andreas podem levar uma pena de contravenção ou pena de prisão com aprisionamento na instalação apropriada do município ou penitenciária estadual.'),
('(8)11', 'Prisão Máxima', 'misdemeanor', 600, 0, 'orange', 'Um cidadão não pode ser preso por mais de 600 minutos, ainda que seus crimes obriguem uma penalidade superior a este tempo, salvo se houver sentença aprovada por um juiz com participação da promotoria.'),
('(8)12', 'Escutas Telefônicas, CCTV e Política de Gravação de Vídeo', 'felony', 0, 0, 'red', 'Uma pessoa que é descoberta violando as leis de escutas telefônicas está sujeita às penalidades de (1)02. Espionagem.'),
('(8)13', 'Política de Exigência e Perseguições', 'misdemeanor', 0, 0, 'orange', 'Os oficiais da lei têm autoridade para seguir os suspeitos em propriedades privadas, se diretamente relacionadas a uma perseguição em andamento. A entrada relacionada a investigações ou outros projetos que não perseguem diretamente um suspeito exigem um mandado.'),
('(8)14', 'Causa Provável e Política de Visão Simples', 'misdemeanor', 0, 0, 'orange', 'Os oficiais da lei têm o poder de apreender e registrar evidências sobre qualquer evento que esteja em sua visão simples, desde que eles tenham uma razão legal para estar onde eles estão localizados no momento.'),
('(8)15', 'Cláusula de Reincidência', 'felony', 0, 0, 'red', 'Um advogado estatal pode cobrar uma pessoa presa que tenha sido anteriormente condenada por pelo menos um crime, com esta cláusula, o que aumentará o tempo devido por cem por cento (100%) para o reincidente.'),
('(8)16', 'Imunidade', 'felony', 0, 0, 'red', 'A pedido de um policial e em troca do testemunho de testemunhas, um advogado do estado pode optar por conceder a uma pessoa uma imunidade parcial ou total.'),
('(8)17', 'Prisão Preventiva', 'misdemeanor', 0, 0, 'orange', 'A prisão preventiva poderá ser decretada como garantia da ordem pública, da ordem econômica, por conveniência da instrução criminal, ou para assegurar a aplicação da lei penal, quando houver prova da existência do crime e indício suficiente de autoria.'),
('(8)18', 'Medidas Cautelares', 'misdemeanor', 0, 0, 'orange', 'Será decretado o cumprimento de medidas cautelares diversas da prisão quando não houver aplicação da prisão preventiva.'),
('(8)19', 'Tentativa', 'misdemeanor', 0, 0, 'orange', 'Uma pessoa que tenta cometer qualquer crime, mas falha ou é impedida ou interceptada em sua consumação, receberá a mesma punição que se a infração tivesse sido cometida.'),
('(8)20', 'Conspiração', 'misdemeanor', 0, 0, 'orange', 'Se duas ou mais pessoas conspirarem para cometer qualquer crime, falsamente e maliciosamente para induzir outro por qualquer crime, ou outro para ser acusado ou preso por qualquer crime, eles serão punidos pela mesma punição que, se a infração tenha sido cometida.'),
('(8)21', 'Solicitação', 'misdemeanor', 0, 0, 'orange', 'A pessoa que solicitar à comissão ou a execução de qualquer crime será punida pela mesma punição que se a infração tenha sido cometida.'),
('(8)22', 'Cláusula do Funcionário Público', 'misdemeanor', 0, 0, 'orange', 'Qualquer crime cometido conscientemente contra um trabalhador do governo ou funcionário da agência estadual, conforme definido pela Constituição do Estado, punirá o agente com a sentença máxima possível permitida por essa entrada de código particular, a menos que um juiz ordene uma sentença reduzida.'),
('(8)23', 'Violação de Armas', 'felony', 0, 0, 'red', 'Uma pessoa que comete um crime quando possuir uma arma de fogo deve ter sua permissão de armas de fogo revogada.'),
('(8)24', 'Cláusula de Cumplicidade Criminal', 'misdemeanor', 0, 0, 'orange', 'Uma pessoa que atua como cúmplice, ajudante, conselheiro ou outro papel de apoio aos atos criminosos tentados ou com êxito na ajuda de outra pessoa, receberá metade da punição atribuída à pessoa que tentou ou cometeu atos criminosos bem-sucedidos.'),
('(8)25', 'Acessório', 'misdemeanor', 0, 0, 'orange', 'Uma pessoa que conscientemente e voluntariamente ajuda outra pessoa que cometeu com sucesso a um ato criminoso receberá metade da punição emitida para a pessoa que cometeu o ato criminoso.')
